1	// Stop hook: Auto-update STATE.md with real metrics from data files
2	const fs = require('fs');
3	const path = require('path');
4	
5	const DATA_DIR = 'd:/ClaudeWorkspace/08_客户跟进/Okki/data';
6	const STATE_FILE = 'd:/ClaudeWorkspace/08_客户跟进/Okki/STATE.md';
7	const TM_FILE = path.join(DATA_DIR, 'tm_conversations_latest.json');
8	const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
9	const CUSTOMERS_DIR = path.join(DATA_DIR, 'customers');
10	const CACHE_FILE = path.join(DATA_DIR, '.state_cache.json');
11	
12	try {
13	  // 1. Read current STATE.md
14	  if (!fs.existsSync(STATE_FILE)) { console.log('[update-state] STATE.md not found'); process.exit(0); }
15	  let stateContent = fs.readFileSync(STATE_FILE, 'utf8');
16	
17	  // 2. Read latest data
18	  const tmData = fs.existsSync(TM_FILE) ? JSON.parse(fs.readFileSync(TM_FILE, 'utf8')) : null;
19	  const chatFiles = fs.existsSync(CHAT_DIR) ? fs.readdirSync(CHAT_DIR).filter(f => f.endsWith('.json')) : [];
20	  const customerFiles = fs.existsSync(CUSTOMERS_DIR) ? fs.readdirSync(CUSTOMERS_DIR).filter(f => f.endsWith('.json')) : [];
21	  const prevCache = fs.existsSync(CACHE_FILE) ? JSON.parse(fs.readFileSync(CACHE_FILE, 'utf8')) : {};
22	
23	  if (!tmData || !tmData.conversations) { console.log('[update-state] No conversation data'); process.exit(0); }
24	
25	  // 3. Extract metrics from data
26	  const now = new Date();
27	  const nowTs = now.getTime();
28	  const nowStr = now.toISOString().slice(0, 16).replace('T', ' ');
29	
30	  const totalConvs = tmData.total || tmData.conversations.length;
31	  const exportedStr = tmData.exportedAt ? new Date(tmData.exportedAt).toISOString().slice(0, 16).replace('T', ' ') : 'unknown';
32	
33	  // Conversation-level stats
34	  let active24h = 0, active7d = 0, sentCount = 0, receivedCount = 0;
35	
36	  for (const conv of tmData.conversations) {
37	    const lct = conv.lastContactTime;
38	    if (lct) {
39	      const age = nowTs - lct;
40	      if (age < 24 * 3600 * 1000) active24h++;
41	      if (age < 7 * 24 * 3600 * 1000) active7d++;
42	    }
43	    if (conv.latestMessage) {
44	      if (conv.latestMessage.messageType === 'send') sentCount++;
45	      else if (conv.latestMessage.messageType === 'received') receivedCount++;
46	    }
47	  }
48	
49	  // Per-conversation stats from chat_history files (light: only read file count, not content)
50	  const chatCount = chatFiles.length;
51	  const customerCount = customerFiles.length;
52	
53	  // 4. Compare with previous cache
54	  let deltaStr = '';
55	  if (prevCache.totalConvs !== undefined) {
56	    const convDelta = totalConvs - prevCache.totalConvs;
57	    const chatDelta = chatCount - prevCache.chatCount;
58	    const custDelta = customerCount - prevCache.customerCount;
59	    const parts = [];
60	    if (convDelta !== 0) parts.push(`总会话 ${convDelta > 0 ? '+' + convDelta : convDelta}`);
61	    if (chatDelta !== 0) parts.push(`聊天记录 ${chatDelta > 0 ? '+' + chatDelta : chatDelta}`);
62	    if (custDelta !== 0) parts.push(`客户 ${custDelta > 0 ? '+' + custDelta : custDelta}`);
63	    deltaStr = parts.length > 0 ? ' (变动: ' + parts.join(', ') + ')' : ' (无变动)';
64	  }
65	
66	  // 5. Save current values to cache
67	  fs.writeFileSync(CACHE_FILE, JSON.stringify({
68	    totalConvs, chatCount, customerCount, active24h, active7d,
69	    lastUpdate: now.toISOString(),
70	    exportedAt: tmData.exportedAt
71	  }, null, 2));
72	
73	  // 6. Build updated STATE.md sections
74	  // Update timestamp
75	  stateContent = stateContent.replace(/最后更新.*/, `最后更新：${nowStr} (hook自动)`);
76	
77	  // Build new metrics table
78	  const newTable = `| 指标 | 数值 |
79	|------|------|
80	| 数据同步时间 | ${exportedStr} |
81	| Hook更新时间 | ${nowStr} 北京时间 |
82	| 总会话 | **${totalConvs}**${deltaStr} |
83	| 聊天历史文件 | **${chatCount}** |
84	| 客户文件 | **${customerCount}** |
85	| 24h内活跃 | **${active24h}** 个会话 |
86	| 7d内活跃 | **${active7d}** 个会话 |
87	| 最新消息-我方 | ${sentCount} 个会话 |
88	| 最新消息-客户方 | ${receivedCount} 个会话（⚠️ latestMessage不=客户回复数,真值需遍历全部消息） |`;
89	
90	  // Replace the old metrics table: everything from "| 指标 | 数值 |" to (and including) the blank line before next "## "
91	  const tableSection = /^\| 指标 \| 数值 \|[\s\S]*?\n(?=## )/m;
92	  if (tableSection.test(stateContent)) {
93	    stateContent = stateContent.replace(tableSection, newTable + '\n\n');
94	  } else {
95	    // Fallback: insert after "## 最新同步结果"
96	    stateContent = stateContent.replace(/(## 最新同步结果\n)/, `$1\n${newTable}\n\n`);
97	  }
98	
99	  // 7. Write back
100	  fs.writeFileSync(STATE_FILE, stateContent);
101	  console.log(`[update-state] STATE.md updated at ${nowStr} | ${totalConvs} convs | ${chatCount} chats | ${customerCount} customers | 24h:${active24h} 7d:${active7d}`);
102	
103	} catch (err) {
104	  console.error('[update-state] Error:', err.message);
105	  process.exit(0); // Never block session exit
106	}
